#include<bits/stdc++.h>
using namespace std;
int I[50000][2],a[100][100],qx,zx,zy,qy,l=1,k,n,m;
const int c2[]={-1,0,1,0},c1[]={0,-1,0,1};
bool vis[100][100];
void print(){
	if(!k)k=1;
	for(int i=1;i<l;i++){
		cout<<'('<<I[i][0]<<','<<I[i][1]<<")->";
	}cout<<'('<<zx<<','<<zy<<')'<<endl;
}
void bfs(int x,int y){
	if(x<1||x>m)return;
    if(y<1||y>n)return;
	if(x==zx&&y==zy){
		print();
		return;
	}
	else{
		for(int i=0;i<4;i++){
			if(a[x+c1[i]][y+c2[i]]&&!(vis[x+c1[i]][y+c2[i]])){
				vis[x][y]=1;
				I[l][0]=x;
				I[l][1]=y;
				l++;
				bfs(x+c1[i],y+c2[i]);
				vis[x][y]=0;
				l--;
			}
		}
	}
}
int main(void){
	cin>>m>>n;
	for(int i=1;i<=m;i++)
		for(int j=1;j<=n;j++)
			cin>>a[i][j];
	cin>>qx>>qy>>zx>>zy;
	bfs(qx,qy);
	if(!k)cout<<-1;
	return false;
}
